  ('retired-7ec62a85-moex-00203', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '有人說績效評估容易造成目標錯置，這句話的意思為何？ 組織中高階人員與低階人員對目標的定義不同 執行任務後發現與既定的策略目標有落差 誤把績效指標當成目的性的組織價值與信仰 組織缺乏學習能力，無法將績效評估結果回饋到新的做法上', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00204', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '下列那一項不屬於布雷克（R. R. Blake）與毛頓（J. S. Mouton）依其「管理格道」所發展之五種 領導類型？ 權威服從式管理  走動式管理  無為式管理  團隊式管理', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00205', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '進行災害管理與應變時，下列何者錯誤？ 需釐清災害種類及性質 分為減災、整備、應變、復原，其中最重要的階段是減災 災害管理各階段均應獨立規劃，以達最大綜效 災害應變的原則，其順序為自助、互助、公助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00206', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '關於我國推動「智慧國家方案」之敘述，下列何者錯誤？ 以促進國家社會整體數位轉型，建構智慧國家新典範 以促進社會整備（Society Ready）為核心 以「數位基盤」、「數位創新」、「數位治理」及「數位包容」為主軸 以「2050實現創新、包容、淨零碳排之智慧國家」為願景', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00207', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '依據史奈德（A. Schneider）和英格恩（H. Ingram）之論點，以新冠肺炎防疫為例，中央流行疫 情指揮中心每日召開直播記者會，公布疫情資訊及說明防疫指引。此較接近下列何種政策工具 類型？ 權威（authoritarian）型  能力建立（capacity-building）型 誘因（incentive）型    管制（regulation）型', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00208', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '在針對某項中長期計畫進行成本效益分析（cost-benefit analysis）時，當計畫產生效益的時間越 長，下列那一個因素對決策的影響越大？ 直接效益  直接成本  折現因子  貨幣單位', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00209', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '當代公共問題的影響範圍往往跨越了專業藩籬，下列何者是錯誤的解決方式？ 採用韋伯（M. Weber）的官僚制度，加強專業分工 以宏觀全局的視野，了解利害關係者所形成的系統問題 消除部門與部門之間僵硬的界線 融合各種專業，提供整合性的解決方法', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00210', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '有關政府與非營利組織之間的互動關係，下列敘述何者錯誤？ 公共治理強調非營利組織參與公共事務的角色 非營利組織應與政府區隔，所以不可接受政府經費補助 非營利組織應受到政府相關法令的約束 政府與非營利組織可以契約外包的方式合作', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00211', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '隨著數位化潮流興起，民眾透過手機、APP和網際網路參與公共政策制定，已成為一種最方便、 直接的民主參與方式，此一發展趨勢稱之為： 應用民主（application democracy）  數位行銷（digital marketing） 線上民主（online democracy）  線上學習（online learning）', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
